import React, { useState } from "react";
import styled from "styled-components";
import { motion } from "framer-motion";
import OptimizedImage from "../ui/OptimizedImage";

/**
 * Partners section displaying organization partners with Meta-inspired UI
 * @returns {JSX.Element} Partners component
 */
const Partners = () => {
  // Partner data with logos and names
  const partners = [
    {
      id: 1,
      name: "UNICEF",
      logo: "/images/partners/unicef-logo.png",
      url: "https://www.unicef.org"
    },
    {
      id: 2,
      name: "World Vision",
      logo: "/images/partners/world-vision-logo.png",
      url: "https://www.worldvision.org"
    },
    {
      id: 3,
      name: "Global Water Initiative",
      logo: "/images/partners/gwi-logo.png",
      url: "https://www.globalwater.org"
    },
    {
      id: 4,
      name: "Bill & Melinda Gates Foundation",
      logo: "/images/partners/gates-foundation-logo.png",
      url: "https://www.gatesfoundation.org"
    },
    {
      id: 5,
      name: "Tanzania Community Development Trust",
      logo: "/images/partners/tcdt-logo.png",
      url: "https://www.tcdt.org"
    },
    {
      id: 6,
      name: "Mastercard Foundation",
      logo: "/images/partners/mastercard-foundation-logo.png",
      url: "https://www.mastercardfdn.org"
    }
  ];

  // Animation variants for staggered animations
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { y: 20, opacity: 0 },
    visible: {
      y: 0,
      opacity: 1,
      transition: {
        duration: 0.5,
        ease: "easeOut"
      }
    }
  };

  return (
    <PartnersSection>
      <SectionContent>
        <SectionHeader>
          <SectionTitle>Our Partners</SectionTitle>
          <SectionDescription>
            Working together with these organizations to create lasting impact and transform communities
          </SectionDescription>
        </SectionHeader>

        <PartnerLogosContainer
          as={motion.div}
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.3 }}
        >
          {partners.map((partner) => (
            <ParallaxWrapper key={partner.id}>
              <PartnerLogoWrapper
                as={motion.a}
                href={partner.url}
                target="_blank"
                rel="noopener noreferrer"
                variants={itemVariants}
              >
                <PartnerLogo>
                  <OptimizedImage src={partner.logo} alt={`${partner.name} logo`} />
                </PartnerLogo>
                <PartnerName>{partner.name}</PartnerName>
              </PartnerLogoWrapper>
            </ParallaxWrapper>
          ))}
        </PartnerLogosContainer>

        <PartnerCta
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ 
            opacity: 1, 
            y: 0,
            transition: { 
              duration: 0.6, 
              ease: "easeOut", 
              delay: 0.3 
            } 
          }}
          viewport={{ once: true, amount: 0.3 }}
        >
          <CtaText>Interested in partnering with us?</CtaText>
          <CtaLink href="/contact-us">Get in touch</CtaLink>
        </PartnerCta>
      </SectionContent>
    </PartnersSection>
  );
};

/**
 * ParallaxWrapper - A component that adds subtle parallax effect to its children
 * @param {Object} props - Component props
 * @returns {JSX.Element} - Parallax component
 */
const ParallaxWrapper = ({ children }) => {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const ref = React.useRef(null);

  const handleMouseMove = (e) => {
    if (!ref.current) return;

    const { left, top, width, height } = ref.current.getBoundingClientRect();
    const x = (e.clientX - left) / width - 0.5;
    const y = (e.clientY - top) / height - 0.5;

    setMousePosition({ x, y });
  };

  return (
    <motion.div 
      ref={ref}
      onMouseMove={handleMouseMove}
      style={{
        position: "relative",
        height: "100%",
        width: "100%",
        display: "flex",
        alignItems: "center",
        justifyContent: "center"
      }}
      animate={{
        rotateY: mousePosition.x * 5,
        rotateX: -mousePosition.y * 5,
        transformPerspective: 1000
      }}
      transition={{ type: "spring", damping: 10, stiffness: 50 }}
    >
      {children}
    </motion.div>
  );
};

// Styled components with 2 spaces indentation
const PartnersSection = styled.section`
  padding: 80px 0;
  background-color: var(--background-white);
`;

const SectionContent = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
`;

const SectionHeader = styled.div`
  text-align: center;
  margin-bottom: 60px;
`;

const SectionTitle = styled.h2`
  font-size: 42px;
  color: var(--text-primary);
  margin-bottom: 16px;
  font-weight: 700;
`;

const SectionDescription = styled.p`
  font-size: 18px;
  color: var(--text-secondary);
  max-width: 700px;
  margin: 0 auto;
  line-height: 1.6;
`;

const PartnerLogosContainer = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 40px;
  margin-bottom: 60px;

  @media (max-width: 1024px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 640px) {
    grid-template-columns: 1fr;
  }
`;

const PartnerLogoWrapper = styled(motion.a)`
  display: flex;
  flex-direction: column;
  align-items: center;
  text-decoration: none;
  transition: transform 0.3s ease;

  &:hover {
    transform: translateY(-8px);

    img {
      opacity: 1;
      filter: none;
    }
  }
`;

const PartnerLogo = styled.div`
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 16px;

  img {
    max-width: 180px;
    max-height: 80px;
    object-fit: contain;
    opacity: 0.8;
    filter: grayscale(30%);
    transition: all 0.4s ease;
  }
`;

const PartnerName = styled.span`
  font-size: 16px;
  font-weight: 500;
  color: var(--text-primary);
  text-align: center;
`;

const PartnerCta = styled(motion.div)`
  text-align: center;
  margin-top: 60px;
  padding: 40px;
  background: linear-gradient(to right, rgba(240,242,245,0.8), rgba(228,230,235,0.8), rgba(240,242,245,0.8));
  border-radius: 12px;
  display: flex;
  flex-direction: column;
  align-items: center;
  overflow: hidden;
  position: relative;
  box-shadow: 0 6px 20px rgba(0, 0, 0, 0.04);

  &::before {
    content: "";
    position: absolute;
    top: 0;
    left: -100%;
    width: 200%;
    height: 100%;
    background: linear-gradient(90deg, 
      rgba(255,255,255,0) 0%, 
      rgba(255,255,255,0.4) 50%, 
      rgba(255,255,255,0) 100%);
    animation: shine 8s infinite linear;
  }

  @keyframes shine {
    from { left: -100%; }
    to { left: 100%; }
  }
`;

const CtaText = styled.p`
  font-size: 20px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: 20px;
  position: relative;
  z-index: 1;
`;

const CtaLink = styled.a`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background-color: var(--primary-color);
  color: white;
  font-weight: 600;
  padding: 12px 28px;
  border-radius: 100px;
  text-decoration: none;
  transition: all 0.2s ease;
  position: relative;
  z-index: 1;

  &:hover {
    background-color: var(--secondary-color);
    transform: translateY(-2px);
    box-shadow: 0 8px 16px rgba(0, 0, 0, 0.1);
  }

  &:active {
    transform: translateY(0);
  }
`;

export default Partners;
